/*
Emitted every time the blend space's triangles are created, removed, or when one of their vertices changes position.
*/
func (self Instance) OnTrianglesUpdated(cb func(), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("triangles_updated"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) TrianglesUpdated() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`triangles_updated`))))
}

